def rearrange_bigger(n):
    s = list(str(n))
    if len(s) == 1:
        return False
    i = len(s) - 2
    while i >= 0 and s[i] >= s[i+1]:
        i -= 1
    if i == -1:
        return False
    j = len(s) - 1
    while s[j] <= s[i]:
        j -= 1
    s[i], s[j] = s[j], s[i]
    s[i+1:] = s[i+1:][::-1]
    return int(''.join(s))
